async function initializeFonts(pdfDoc) {

  const helveticaFont = await pdfDoc.embedFont(StandardFonts.Helvetica)

  let TimesRomanBold = await pdfDoc.embedFont(StandardFonts.TimesRomanBold);
  let TimesRomanItalic = await pdfDoc.embedFont(StandardFonts.TimesRoman);



  let fontUrl = getStore("Roboto-Bold.ttf");
  const fontBytes =  await fetch(fontUrl).then((res) => res.arrayBuffer());
  const RobotoBold = await pdfDoc.embedFont(fontBytes, { subset: true });



  let fontUrlRoboto_italic = getStore("ggSans-Medium.ttf");
  const fontBytes2 =  await fetch(fontUrlRoboto_italic).then((res) => res.arrayBuffer());
  const GSansBold = await pdfDoc.embedFont(fontBytes2,{ subset: true });


  let fontUrlGSB = getStore("Roboto-Regular.ttf");
  const fontBytes_GSB =  await fetch(fontUrlGSB).then((res) => res.arrayBuffer());
  const RobotoRegular = await pdfDoc.embedFont(fontBytes_GSB, { subset: true });


  let fontUrlariaR = getStore("arial_bold.ttf");
  const fbAr =  await fetch(fontUrlariaR).then((res) => res.arrayBuffer());
  let ariaR = await pdfDoc.embedFont(fbAr,{ subset: true });






  return {
    "gSans":GSansBold,
    "roboto":helveticaFont,
    "roboto_bold":RobotoBold,
    "roboto_regular":RobotoRegular,
    "aria_regurlar": ariaR,
    "TimesRomanBold": TimesRomanBold,
    "TimesRomanItalic":TimesRomanItalic
  }


}





export async function generateN400PDf(data, psn400, blob, add) {
  // console.log(data);

    let element = psn400 || {};
    

    data && element && ObjectKeys(data).map(fld=>{
      if(element[fld] && data[fld]){
        element[fld].text = data[fld];
      }
    })

    const url2 = getStore("N400_form.pdf");
    // "https://qvamarkets.com/gql_api/getStatic?fileName=I589_form.pdf";

    const existingPdfBytes = await fetch(url2).then((res) =>
      res.arrayBuffer()
    );

    const pdfDoc = await PDFDocument.load(existingPdfBytes,{ignoreEncryption: true})

    pdfDoc.registerFontkit(fontkit);

    const fonstP = await initializeFonts(pdfDoc);

    const pages = pdfDoc.getPages()
    const firstPage = pages[0]
    const { width, height } = firstPage.getSize()
    updStore("pdfSize", { width, height, pages : pages.length })
    

    let pngUrl = getStore("b64_signature");
    // || 'https://www.hrmfinance.com/data/signature.png';
    let pngImage = null;
    if(pngUrl){
      const pngImageBytes = await fetch(pngUrl).then((res) => res.arrayBuffer())
      pngImage = await pdfDoc.embedPng(pngImageBytes)
    
    }
  



    element && ObjectKeys(element).map(async elmId=>{
      let elm = element[elmId];
      if(elm){
        
        let pageNo = elm.pageNo;

        let pgSz = pages?.[pageNo]?.getSize();


      
        if(elm.type==="text"){
          let alph = 4
          let Stx = elm.text?elm.text.toString() : ""
          if(elmId==="todayDate"){
            Stx =  parseDateMMDDYYYY((new Date()).getTime());
          }
          pages[pageNo]?.drawText(Stx, {
            x: elm.x,
            y:  pgSz.height - elm.y ,
            size: elm.size || 10,
            font: fonstP[elm.font] || fonstP.TimesRomanItalic,      
            color:elm.color ? rgb(elm.color[0]/255 , elm.color[1]/255 , elm.color[2]/255 ) :  rgb(0, 0.1, 0.1)
          })
        }
        else if(elm.type==="multi_line"){
          let Stx = elm.text?elm.text.toString() : ""
          let lineHeight = elm.lineHeight || 10;
          const multiText = layoutMultilineText(Stx, {
              alignment: 'left', 
              font: fonstP[elm.font] || fonstP.TimesRomanItalic ,
              fontSize: elm.size || 9,
              lineHeight: lineHeight ,
              bounds: { width: width - 100, height: 500  }
          })
          let startingPositon = pgSz.height - elm.y;

          for(let i = 0; i < multiText.lines.length; i++) {
            pages[pageNo].drawText(`${multiText.lines[i].text}`, {
                x: elm.x,
                y: startingPositon,
                size: elm.size || 9,
                maxWidth: width - 100,
                font: fonstP[elm.font] || fonstP.TimesRomanItalic,
                color:elm.color ? rgb(elm.color[0]/255 , elm.color[1]/255 , elm.color[2]/255 ) :  rgb(0, 0.1, 0.1)
              
              })
            // move position down
              startingPositon = startingPositon - (lineHeight)
            }
            return startingPositon
          
        }
        else if(elm.type==="textboxn"){

          let letters = (elm.text?elm.text.toString() : elm.id.toString()).split('');
        
          letters?.map((lt, indx)=>{
            pages[pageNo]?.drawText(lt, {
              x: elm.x + (indx * elm.space),
              y:  pgSz.height - elm.y ,
              size: elm.size || 10,
              font: fonstP[elm.font] || fonstP.TimesRomanItalic,     
              color:elm.color ? rgb(elm.color[0]/255 , elm.color[1]/255 , elm.color[2]/255 ) :  rgb(0, 0.1, 0.1)
            })
          })

          
        }
        else if(elm.type==="checkBox"){   
          let alph = 4     
          let yAx = pgSz?.height  - elm.y ;
          let svgPath = "M21,7L9,19L3.5,13.5L4.91,12.09L9,16.17L19.59,5.59L21,7Z";
          pages[pageNo]?.moveTo( elm.x+2,yAx);
          pages[pageNo]?.drawSvgPath(svgPath, { borderColor: elm.color ? rgb(elm.color[0]/255 , elm.color[1]/255 , elm.color[2]/255 ) :  rgb(0, 0, 0), borderWidth: 1 , scale: 0.5})
          
        }
        else if(elm.type==="line"){
          let color =  elm.color || [25,25,25]; 
          pages[pageNo]?.drawRectangle({
            x: elm.x,
            y:  pgSz.height - elm.y ,
            width: elm.width,
            height: elm.height, 
            color: color ? rgb(color[0]/255 , color[1]/255 , color[2]/255 ) :  rgb(0, 0.1, 0.1)
          });
        }
        else if(elm.type==="image"){
          pngImage && pages[pageNo].drawImage(pngImage, {
            x: elm.x,
            y:  pgSz.height - elm.y ,
            width:  elm.w,
            height: elm.h,
          })
        }
      }
    })


    
  drawRuler(pages[1], height, fonstP.TimesRomanBold)



  if(blob){
    const pdfBytes = await pdfDoc.save();
    return blobfromArray(pdfBytes)
  }
  else{
    return pdfDoc.saveAsBase64({ dataUri: true });
  }
  
    
 
}








